//GRID
if(tGrpId == "{G.GRPID}" && tColId =="{I.COLID}"){
	alog("LAST_ROWID = " + tRowId);
	//그리드 일때
	//전체 값중에 TEXT, VALUE만 변경
	var origin = mygrid{G.GRPID}.cells(tRowId,mygrid{G.GRPID}.getColIndexById(tColId)).getValue();
	alog("before = " + origin);
	var tArr = origin.split("^"); ////CD^NM^GRPID
	tArr[0] = tJsonObj.CD;
	tArr[1] = tJsonObj.NM;	
	tArr[2] = "{G.GRPID}";//GRPID
	alog("after = " + tArr[0] + "^" + tArr[1] + "^" + tArr[2]);

	mygrid{G.GRPID}.cells(tRowId,mygrid{G.GRPID}.getColIndexById(tColId)).setValue(tArr[0] + "^" + tArr[1] + "^" + tArr[2] );
}
